mapper.select:
        select * from (select *
		from VzDataQuality.dbo.tb_collectionrule


                column_code!=#{map.old_name}


		) as m where m.task_id=#{map.task_id} and m.column_code=#{map.column_code}

select * from VzDataQuality.dbo.tb_collectionrule m1
left join VzDataQuality.dbo.DataElements m2
on m1.data_id=m2.id where m2.DataType=#{map.field_type} and m1.task_id=#{map.task_id}
